{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyMZPKo58Cpdo/SgEk2uGTIA"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","execution_count":null,"metadata":{"id":"BdCwUSFSR5fE"},"outputs":[],"source":["import streamlit as st\n","import sqlite3\n","import hashlib\n","import pandas as pd\n","import numpy as np\n","import tensorflow as tf\n","import matplotlib.pyplot as plt\n","import seaborn as sns\n","import yfinance as yf\n","import datetime\n","from sklearn.preprocessing import MinMaxScaler\n","\n","# ---------------- DATABASE ----------------\n","conn = sqlite3.connect(\"users.db\", check_same_thread=False)\n","c = conn.cursor()\n","\n","c.execute(\"\"\"\n","CREATE TABLE IF NOT EXISTS users(\n","    username TEXT PRIMARY KEY,\n","    password TEXT\n",")\n","\"\"\")\n","conn.commit()\n","\n","# ---------------- PASSWORD HASH ----------------\n","def make_hash(password):\n","    return hashlib.sha256(password.encode()).hexdigest()\n","\n","def check_hash(password, hashed):\n","    return make_hash(password) == hashed\n","\n","# ---------------- AUTH FUNCTIONS ----------------\n","def register_user(username, password):\n","    c.execute(\"INSERT INTO users(username,password) VALUES(?,?)\",\n","              (username, make_hash(password)))\n","    conn.commit()\n","\n","def login_user(username, password):\n","    c.execute(\"SELECT password FROM users WHERE username=?\", (username,))\n","    data = c.fetchone()\n","    if data and check_hash(password, data[0]):\n","        return True\n","    return False\n","\n","# ---------------- SESSION ----------------\n","if \"logged_in\" not in st.session_state:\n","    st.session_state.logged_in = False\n","\n","if \"username\" not in st.session_state:\n","    st.session_state.username = \"\"\n","\n","\n","# =====================================================\n","# ================= LOGIN PAGE ========================\n","# =====================================================\n","\n","def login_page():\n","    st.title(\"🔐 Stock Prediction Login\")\n","\n","    menu = st.sidebar.selectbox(\"Menu\", [\"Login\", \"Register\"])\n","\n","    if menu == \"Login\":\n","        username = st.text_input(\"Username\")\n","        password = st.text_input(\"Password\", type=\"password\")\n","\n","        if st.button(\"Login\"):\n","            if login_user(username, password):\n","                st.success(\"Login Successful!\")\n","                st.session_state.logged_in = True\n","                st.session_state.username = username\n","                st.rerun()\n","            else:\n","                st.error(\"Invalid Username or Password\")\n","\n","    else:  # Register\n","        st.subheader(\"Create New Account\")\n","        new_user = st.text_input(\"Username\")\n","        new_password = st.text_input(\"Password\", type=\"password\")\n","\n","        if st.button(\"Register\"):\n","            try:\n","                register_user(new_user, new_password)\n","                st.success(\"Account Created! Now Login.\")\n","            except:\n","                st.error(\"Username already exists\")\n","\n","\n","# =====================================================\n","# =============== STOCK PREDICTION APP =================\n","# =====================================================\n","\n","def stock_app():\n","\n","    st.sidebar.success(f\"Logged in as {st.session_state.username}\")\n","\n","    if st.sidebar.button(\"Logout\"):\n","        st.session_state.logged_in = False\n","        st.session_state.username = \"\"\n","        st.rerun()\n","\n","    # ---------------- YOUR ORIGINAL CODE ----------------\n","\n","    start = \"2010-01-01\"\n","    end = datetime.date.today().strftime(\"%Y-%m-%d\")\n","\n","    st.title(\"📈 Stock Prediction Trend\")\n","\n","    user_input = st.text_input(\"Enter Stock Ticker\", \"GOOG\")\n","\n","    df = yf.download(user_input, start, end)\n","\n","    # Describing Data\n","    st.subheader(\"Data Description\")\n","    st.write(df.describe())\n","\n","    # Visualization\n","    st.subheader(\"Closing Price Vs Time Chart\")\n","    fig = plt.figure(figsize=(12,6))\n","    plt.plot(df.Close,\"g\", label=\"Closing Price\")\n","    plt.legend()\n","    st.pyplot(fig)\n","\n","    st.subheader(\"Closing Price Vs Time Chart with 100MA\")\n","    ma100 = df.Close.rolling(100).mean()\n","    fig = plt.figure(figsize=(12,6))\n","    plt.plot(df.Close,\"g\")\n","    plt.plot(ma100,\"r\")\n","    st.pyplot(fig)\n","\n","    st.subheader(\"Closing Price Vs Time Chart with 100MA & 200MA\")\n","    ma200 = df.Close.rolling(200).mean()\n","    fig = plt.figure(figsize=(12,6))\n","    plt.plot(df.Close,\"g\")\n","    plt.plot(ma100,\"r\")\n","    plt.plot(ma200,\"b\")\n","    st.pyplot(fig)\n","\n","    # Train/Test split\n","    data_train  = pd.DataFrame(df[\"Close\"][0:int(len(df)*0.80)])\n","    data_test   = pd.DataFrame(df[\"Close\"][int(len(df)*0.80):])\n","\n","    scaler = MinMaxScaler(feature_range=(0,1))\n","    scaler.fit(data_train)\n","\n","    model = tf.keras.models.load_model(\"Keras_Model.keras\")\n","\n","    future_days = st.sidebar.radio(\"Predict future days:\", (1,5,7))\n","\n","    last_100_days = df[\"Close\"].tail(100).values.reshape(-1,1)\n","    last_100_days_scaled = scaler.transform(last_100_days)\n","\n","    future_predictions = []\n","    current_input = last_100_days_scaled\n","\n","    for i in range(future_days):\n","        current_input_reshaped = current_input.reshape(1,100,1)\n","        next_prediction = model.predict(current_input_reshaped, verbose=0)\n","        future_predictions.append(next_prediction[0,0])\n","        current_input = np.append(current_input[1:], next_prediction, axis=0)\n","\n","    future_predictions = scaler.inverse_transform(np.array(future_predictions).reshape(-1,1))\n","\n","    st.subheader(\"Prediction Result\")\n","    st.success(f\"Predicted price after {future_days} day(s) = ${future_predictions[-1][0]:.2f}\")\n","\n","    # Plot future\n","    last_date = df.index[-1]\n","    future_dates = pd.bdate_range(start=last_date + pd.Timedelta(days=1), periods=future_days)\n","\n","    connected_predictions = np.insert(future_predictions.flatten(),0,df.Close.iloc[-1])\n","    connected_dates = future_dates.insert(0,last_date)\n","\n","    fig = plt.figure(figsize=(12,6))\n","    plt.plot(df.index, df.Close, label=\"Historical\")\n","    plt.plot(connected_dates, connected_predictions, label=\"Future\", color=\"red\")\n","    plt.legend()\n","    st.pyplot(fig)\n","\n","\n","# =====================================================\n","# ================== MAIN ROUTER ======================\n","# =====================================================\n","\n","if st.session_state.logged_in:\n","    stock_app()\n","else:\n","    login_page()"]}]}